uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 c =vec2(vUv.x-0.5,vUv.y-0.5)*uAspect.xy;
float rad_hq = log(length(c))*q26;
float ang_hq = -atan(c.x,c.y)*q27 + rad_hq*q24 + q23;
vec2 polar =vec2(ang_hq/asin(1)*2, rad_hq-q25);
vUv = fract(polar.yx);

vec2 hor = vec2 (uTexSize.z,0)*4;
vec2 ver = vec2 (0,uTexSize.w)*4;
float dx = lum(GetBlur1 (vUv-hor) - GetBlur1 (vUv+hor));
float dy = lum(GetBlur1 (vUv-ver) - GetBlur1 (vUv+ver));
vec2 dz = vec2 (dx,dy);

vec3 ret1 = GetPixel(vUv);
vUv = rs;
vUv = cos(vUv*3.14*4 - vec2(0,10)*q20) - 8*dz;;
vec3 dots = clamp01(.02/length(vUv))*hue_shader;

ret = ret1;
ret = mix(mix(ret.x*vec3(3,2,0),vec3(0,-0.8,0.5),clamp01(ret.y))
          ,3
          ,clamp01(ret.z-ret.x));

ret = mix(ret,dots,0.92)*6;
//ret = GetPixel(uvo);

  fragColor = ret;
}
